@app.route('/venues')
def venues_page():
    venues = load_venues()
    capacity_filters = ['Small', 'Medium', 'Large']

    capacity_filter = request.args.get('capacity_filter', '')

    def capacity_category(cap):
        if cap < 1000:
            return 'Small'
        elif cap < 3000:
            return 'Medium'
        else:
            return 'Large'

    filtered_venues = []
    for v in venues:
        cat = capacity_category(v['capacity'])
        if capacity_filter == '' or capacity_filter == cat:
            filtered_venues.append(v)

    return render_template('venues.html', venues=filtered_venues, capacity_filters=capacity_filters)


