@app.route('/schedules')
def event_schedules():
    schedules = load_schedules()
    events = load_events()
    return render_template('schedules.html', schedules=schedules, events=events)


# Route: /bookings
@app.route('/bookings')
def bookings_summary():
    bookings = load_bookings()

    # Process booking cancellation if requested
    cancel_booking_id = request.args.get('cancel_booking_id', '')
    if cancel_booking_id.isdigit():
        cancel_id = int(cancel_booking_id)
        updated = False
        for b in bookings:
            if b['booking_id'] == cancel_id and b['status'] != 'Cancelled':
                b['status'] = 'Cancelled'
                updated = True
                break

        if updated:
            try:
                with open(os.path.join(DATA_DIR, 'bookings.txt'), 'w', encoding='utf-8') as f:
                    for b in bookings:
                        f.write(f"{b['booking_id']}|{b['event_id']}|{b['customer_name']}|{b['booking_date']}|{b['ticket_count']}|{b['ticket_type']}|{b['total_amount']}|{b['status']}\n")
            except Exception:
                pass

    return render_template('bookings.html', bookings=bookings)


if __name__ == '__main__':
    app.run(debug=True, port=5000)

