                    inquiry['customer_email'],
                    inquiry['customer_phone'],
                    inquiry['message'],
                    inquiry['inquiry_date'],
                    inquiry['status']
                ])
                f.write(line + '\n')
    except IOError:
        pass


def read_favorites():
