# Route implementations

@app.route('/')
def root_redirect():
    return redirect(url_for('dashboard'))


@app.route('/dashboard')
def dashboard():
    # Display featured properties - we'll consider as available properties with status 'Available' - get first 5 sorted by property_id ascending
    properties = read_properties()
    featured_properties = [p for p in properties if p['status'] == 'Available']
    featured_properties.sort(key=lambda x: x['property_id'])
    featured_properties = featured_properties[:5]
    return render_template('dashboard.html', featured_properties=featured_properties)


@app.route('/properties')
def property_search():
    properties = read_properties()
    # Show only available properties
    available_props = [p for p in properties if p['status'] == 'Available']
    return render_template('property_search.html', properties=available_props)


@app.route('/property/<int:property_id>')
def property_details(property_id):
    properties = read_properties()
    prop = next((p for p in properties if p['property_id'] == property_id), None)
    if not prop:
        # Could do 404, but spec doesn't specify - render page with no property could be confusing, safest to 404
        return "Property not found", 404
    return render_template('property_details.html', property=prop)


@app.route('/property/<int:property_id>/add_to_favorites', methods=['POST'])
def add_to_favorites(property_id):
    favorites = read_favorites()
    properties = read_properties()
    prop = next((p for p in properties if p['property_id'] == property_id), None)
    if not prop:
        return "Property not found", 404
    # Check if already in favorites
    if any(f['property_id'] == property_id for f in favorites):
        # Already in favorites, redirect to favorites page
        return redirect(url_for('my_favorites'))
    # Id for new favorite
    new_fav_id = max([f['favorite_id'] for f in favorites], default=0) + 1
    today_str = datetime.today().strftime('%Y-%m-%d')
    favorites.append({
        'favorite_id': new_fav_id,
        'property_id': property_id,
        'added_date': today_str
    })
    write_favorites(favorites)
    return redirect(url_for('my_favorites'))


@app.route('/property/<int:property_id>/inquiry', methods=['GET'])
def property_inquiry_form(property_id):
    properties = read_properties()
    selected_property = next((p for p in properties if p['property_id'] == property_id), None)
    if not selected_property:
        return "Property not found", 404
    # For dropdown on inquiry form, pass all available properties
    available_props = [p for p in properties if p['status'] == 'Available']
    return render_template('property_inquiry.html', properties=available_props, selected_property=selected_property)


@app.route('/property/<int:property_id>/inquiry', methods=['POST'])
def submit_inquiry(property_id):
    properties = read_properties()
    prop = next((p for p in properties if p['property_id'] == property_id), None)
    if not prop:
        return "Property not found", 404
    # Extract form data
    customer_name = request.form.get('customer_name')
    customer_email = request.form.get('customer_email')
    customer_phone = request.form.get('customer_phone')
    message = request.form.get('message')
    # Validate form data - minimal: all required
    if not all([customer_name, customer_email, customer_phone, message]):
        # Minimal error response (no template specified)
        return "Missing form data", 400
    inquiries = read_inquiries()
    new_inquiry_id = max([iq['inquiry_id'] for iq in inquiries], default=0) + 1
    today_str = datetime.today().strftime('%Y-%m-%d')
    new_inquiry = {
        'inquiry_id': new_inquiry_id,
        'property_id': property_id,
        'customer_name': customer_name,
        'customer_email': customer_email,
        'customer_phone': customer_phone,
        'message': message,
        'inquiry_date': today_str,
        'status': 'Pending'
    }
    inquiries.append(new_inquiry)
    write_inquiries(inquiries)
    return redirect(url_for('my_inquiries'))


@app.route('/inquiries')
def my_inquiries():
    inquiries = read_inquiries()
    inquiries.sort(key=lambda x: x['inquiry_date'], reverse=True)  # Newest first
    inquiry_status_filter_values = ['Pending', 'Contacted', 'Resolved']
    return render_template('my_inquiries.html', inquiries=inquiries, inquiry_status_filter_values=inquiry_status_filter_values)


@app.route('/inquiries/delete/<int:inquiry_id>', methods=['POST'])
def delete_inquiry(inquiry_id):
    inquiries = read_inquiries()
    original_len = len(inquiries)
    inquiries = [iq for iq in inquiries if iq['inquiry_id'] != inquiry_id]
    if len(inquiries) == original_len:
        # Inquiry not found
        return "Inquiry not found", 404
    write_inquiries(inquiries)
    return redirect(url_for('my_inquiries'))


@app.route('/favorites')
def my_favorites():
    favorites = read_favorites()
    properties = read_properties()
    fav_property_ids = {f['property_id'] for f in favorites}
    # Only include properties in favorites that exist and are available
    favorite_properties = [p for p in properties if p['property_id'] in fav_property_ids and p['status'] == 'Available']
    return render_template('my_favorites.html', favorite_properties=favorite_properties)


@app.route('/favorites/remove/<int:property_id>', methods=['POST'])
def remove_from_favorites(property_id):
    favorites = read_favorites()
    original_len = len(favorites)
    favorites = [f for f in favorites if f['property_id'] != property_id]
    if len(favorites) == original_len:
        # Not present
        return "Favorite not found", 404
    write_favorites(favorites)
    return redirect(url_for('my_favorites'))


@app.route('/agents')
def agent_directory():
    agents = read_agents()
    return render_template('agents.html', agents=agents)


@app.route('/locations')
def locations_page():
    locations = read_locations()
    return render_template('locations.html', locations=locations)


if __name__ == '__main__':
    app.run(debug=True)

