    menu = read_menu()
    dish_names = {d['dish_id']: d['name'] for d in menu}
    user_reviews = []
    for r in reviews:
        if r['username'] == CURRENT_USERNAME:
            user_reviews.append({
                'review_id': r['review_id'],
                'dish_name': dish_names.get(r['dish_id'], 'Unknown'),
                'rating': r['rating'],
                'review_text': r['review_text'],
                'review_date': r['review_date']
            })
    return render_template('my_reviews.html', reviews=user_reviews)


@app.route('/write_review', methods=['GET', 'POST'])
def write_review():
    menu = read_menu()
    dishes_simple = [{'dish_id': d['dish_id'], 'name': d['name']} for d in menu]

    if request.method == 'GET':
        return render_template('write_review.html', dishes=dishes_simple)

    dish_id_str = request.form.get('dish_id', '').strip()
    rating_str = request.form.get('rating', '').strip()
    review_text = request.form.get('review_text', '').strip()

    errors = {}

    try:
        dish_id = int(dish_id_str)
        if dish_id not in [d['dish_id'] for d in menu]:
            errors['rating'] = 'Please select a valid dish.'
    except ValueError:
        errors['rating'] = 'Please select a valid dish.'

    try:
        rating = int(rating_str)
        if rating < 1 or rating > 5:
            errors['rating'] = 'Rating must be between 1 and 5.'
    except ValueError:
        if 'rating' not in errors:
            errors['rating'] = 'Rating must be between 1 and 5.'

    if review_text == '':
        errors['review_text'] = 'Review text cannot be empty.'

    if errors:
        return render_template('write_review.html', dishes=dishes_simple, errors=errors, dish_id=dish_id_str, rating=rating_str, review_text=review_text)

    reviews = read_reviews()
    max_id = max([r['review_id'] for r in reviews], default=0)
    new_id = max_id + 1
    today = datetime.now().strftime('%Y-%m-%d')
    new_review = {
        'review_id': new_id,
        'username': CURRENT_USERNAME,
        'dish_id': dish_id,
        'rating': rating,
        'review_text': review_text,
        'review_date': today
    }
    reviews.append(new_review)
    write_reviews(reviews)

    return redirect(url_for('my_reviews'))


@app.route('/profile', methods=['GET', 'POST'])
def profile():
    users = read_users()
    user_profile = users.get(CURRENT_USERNAME, {'username': CURRENT_USERNAME, 'email': ''})

    if request.method == 'GET':
        return render_template('profile.html', user_profile={'username': user_profile['username'], 'email': user_profile.get('email', '')})

    email = request.form.get('email', '').strip()
    errors = {}
    if '@' not in email or '.' not in email or len(email)<5:
        errors['email'] = 'Invalid email address.'

    if errors:
        return render_template('profile.html', errors=errors, user_profile={'username': user_profile['username'], 'email': email})

    # Update file
    all_users = read_users()
    if CURRENT_USERNAME in all_users:
        all_users[CURRENT_USERNAME]['email'] = email
        path = os.path.join(DATA_DIR, 'users.txt')
        with _file_lock:
            with open(path, 'w', encoding='utf-8') as f:
                for u in all_users.values():
                    line = '|'.join([u['username'], u['email'], u['phone'], u['full_name']])
                    f.write(line + '\n')

    return render_template('profile.html', user_profile={'username': CURRENT_USERNAME, 'email': email})


if __name__ == '__main__':
    app.run(debug=True)


