                f.write(line + '\n')


# Flask routes

@app.route('/')
def root_redirect():
    return redirect(url_for('dashboard'))


@app.route('/dashboard')
def dashboard():
    username = CURRENT_USERNAME
    menu_data = read_menu()
    featured_dishes = [
        {'dish_id': d['dish_id'], 'name': d['name'], 'price': d['price'], 'description': d['description']}
        for d in menu_data[:3]
    ]
    reservations = read_reservations()
    upcoming_reservations = [
        {"reservation_id": r["reservation_id"], "date": r["date"], "time": r["time"], "party_size": r["party_size"], "status": r["status"]}
        for r in reservations if r["username"] == username and r["status"] == "Upcoming"
    ]
    return render_template('dashboard.html', username=username, featured_dishes=featured_dishes, upcoming_reservations=upcoming_reservations)


@app.route('/menu')
def menu():
    menus = read_menu()
    return render_template('menu.html', menus=menus)


@app.route('/dish/<int:dish_id>')
def dish_details(dish_id):
    menu_list = read_menu()
    dish = next((d for d in menu_list if d['dish_id'] == dish_id), None)
    if dish is None:
        return "Dish not found", 404
    return render_template('dish_details.html', dish=dish)


@app.route('/make_reservation', methods=['GET', 'POST'])
def make_reservation():
    if request.method == 'GET':
        return render_template('make_reservation.html')

    guest_name = request.form.get('guest_name', '').strip()
    party_size_str = request.form.get('party_size', '').strip()
    reservation_date = request.form.get('reservation_date', '').strip()

    errors = {}

    if not guest_name:
        errors['guest_name'] = 'Guest name is required.'

    try:
        party_size = int(party_size_str)
        if party_size < 1 or party_size > 10:
            errors['party_size'] = 'Party size must be between 1 and 10.'
    except ValueError:
        errors['party_size'] = 'Invalid party size.'

    try:
        dt = datetime.strptime(reservation_date, '%Y-%m-%d').date()
        if dt < datetime.now().date():
            errors['reservation_date'] = 'Reservation date cannot be in the past.'
    except:
        errors['reservation_date'] = 'Invalid date format.'

    if errors:
        return render_template('make_reservation.html', errors=errors, guest_name=guest_name, party_size=party_size_str, reservation_date=reservation_date)

    users = read_users()
    user = users.get(CURRENT_USERNAME)
    if user is None:
        errors['guest_name'] = 'User information not found.'
        return render_template('make_reservation.html', errors=errors, guest_name=guest_name, party_size=party_size_str, reservation_date=reservation_date)

    phone = user['phone']
    email = user['email']

    reservations = read_reservations()
    max_id = max([r['reservation_id'] for r in reservations], default=0)
    new_id = max_id + 1

    new_reservation = {
        'reservation_id': new_id,
        'username': CURRENT_USERNAME,
        'guest_name': guest_name,
        'phone': phone,
        'email': email,
        'party_size': party_size,
        'date': reservation_date,
        'time': '19:00',  # fixed reservation time
        'special_requests': '',
        'status': 'Upcoming'
    }

    reservations.append(new_reservation)
    write_reservations(reservations)

    return redirect(url_for('my_reservations'))


@app.route('/my_reservations')
def my_reservations():
    reservations = read_reservations()
    user_reservations = []
    for r in reservations:
        if r['username'] == CURRENT_USERNAME:
            user_reservations.append({
                'reservation_id': r['reservation_id'],
                'date': r['date'],
                'time': r['time'],
                'party_size': r['party_size'],
                'status': r['status']
            })
    return render_template('my_reservations.html', reservations=user_reservations)


@app.route('/cancel_reservation/<int:reservation_id>', methods=['POST'])
def cancel_reservation(reservation_id):
    reservations = read_reservations()
    changed = False
    for r in reservations:
        if r['reservation_id'] == reservation_id and r['username'] == CURRENT_USERNAME:
            r['status'] = 'Cancelled'
            changed = True
            break
    if changed:
        write_reservations(reservations)
    return redirect(url_for('my_reservations'))


@app.route('/waitlist', methods=['GET', 'POST'])
def waitlist():
    waitlist = read_waitlist()

    user_active = [w for w in waitlist if w['username'] == CURRENT_USERNAME and w['status'] == 'Active']

    if request.method == 'GET':
        user_position = None
        if user_active:
            waitlist_active_sorted = sorted([w for w in waitlist if w['status'] == 'Active'], key=lambda x: x['join_time'])
            for idx, item in enumerate(waitlist_active_sorted, start=1):
                if item['username'] == CURRENT_USERNAME:
                    user_position = idx
                    break
        return render_template('waitlist.html', user_position=user_position)

    # POST
    party_size_str = request.form.get('party_size', '').strip()
    errors = {}
    try:
        party_size = int(party_size_str)
        if party_size < 1:
            errors['party_size'] = 'Party size must be at least 1.'
    except ValueError:
        errors['party_size'] = 'Invalid party size.'

    user_position = None
    if user_active:
        waitlist_active_sorted = sorted([w for w in waitlist if w['status'] == 'Active'], key=lambda x: x['join_time'])
        for idx, item in enumerate(waitlist_active_sorted, start=1):
            if item['username'] == CURRENT_USERNAME:
                user_position = idx
                break

    if errors:
        return render_template('waitlist.html', errors=errors, user_position=user_position)

    if user_active:
        # User already in waitlist, refresh page with position
        return render_template('waitlist.html', user_position=user_position)

    max_id = max([w['waitlist_id'] for w in waitlist], default=0)
    new_id = max_id + 1
    join_time = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
    new_entry = {
        'waitlist_id': new_id,
        'username': CURRENT_USERNAME,
        'party_size': party_size,
        'join_time': join_time,
        'status': 'Active'
    }
    waitlist.append(new_entry)
    write_waitlist(waitlist)

    # Compute new position
    waitlist_active_sorted = sorted([w for w in waitlist if w['status'] == 'Active'], key=lambda x: x['join_time'])
    user_position = None
    for idx, item in enumerate(waitlist_active_sorted, start=1):
        if item['username'] == CURRENT_USERNAME:
            user_position = idx
            break

    return render_template('waitlist.html', user_position=user_position)


