        with open(path, 'r', encoding='utf-8') as f:
            for line in f:
                line=line.strip()
                if not line:
                    continue
                parts = line.split('|')
                if len(parts) != 8:
                    continue
                try:
                    dish_id = int(parts[0])
                    price = float(parts[3])
                    avg_rating = float(parts[7])
                    dish = {
                        'dish_id': dish_id,
